document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("languageDropdown"),n=document.getElementById("languageList"),t=document.getElementById("arrowIcon");if(!e||!n||!t)return;const s=document.querySelector(".preheader__lang"),d=document.querySelector(".nav__wrapper"),a=()=>{!s||!d||(window.innerWidth<=980?d.contains(e)||d.insertBefore(e,document.querySelector(".menu__mob-btn")):s.contains(e)||s.appendChild(e))};a(),window.addEventListener("resize",a),e.addEventListener("click",()=>{toggleDropdown(n,t)}),document.addEventListener("click",o=>{e.contains(o.target)||n.contains(o.target)||closeDropdown(n,t)}),document.addEventListener("keydown",o=>{o.key==="Escape"&&closeDropdown(n,t)})});const toggleDropdown=(e,n)=>{e.classList.contains("open")?closeDropdown(e,n):(e.classList.add("open"),n.classList.add("rotate"))},closeDropdown=(e,n)=>{e.classList.remove("open"),n.classList.remove("rotate")};
